'use client';
import { Button } from '@/components/ui';
import { useCompare } from '@/components/CompareContext';

export function ToolActions({ slug }: { slug: string }) {
  const { has, toggle } = useCompare();
  return (
    <div style={{ marginTop: 24, display: 'flex', gap: 10, flexWrap: 'wrap' }}>
      <Button variant="primary" onClick={() => window.open(`https://${slug}.example`, '_blank')}>
        Website besuchen ↗
      </Button>
      <Button variant="ghost" onClick={() => toggle(slug)}>
        {has(slug) ? '✓ im Vergleichskorb' : '+ Zum Vergleich hinzufügen'}
      </Button>
    </div>
  );
}
